import { describe, expect, it } from 'vitest';
import {
  resolveNativeToolFamily,
  formatQwenToolsSystemBlock,
  parseQwenNativeToolCalls,
  formatQwenToolResultTurn,
  formatQwenAssistantToolCallTurn,
  buildMistralAvailableToolsSegment,
  generateMistralToolCallId,
  parseMistralNativeToolCalls,
  formatMistralToolCallsSegment,
  formatMistralToolResultSegment,
  renderMistralV3InstructPrompt,
  formatGemma4ToolDeclarationBlock,
  parseGemma4NativeToolCalls,
  formatGemma4ToolCallTurn,
  formatGemma4ToolResultTurn,
  parseNativeToolCalls,
  formatNativeToolsDeclaration,
  type NativeToolFamily,
  type MistralRenderableMessage,
} from '../src/native-tool-formats';
import type { AgenticToolCall, AgenticToolDefinition } from '../src/agentic-chat';

const WEATHER_TOOL: AgenticToolDefinition = {
  type: 'function',
  function: {
    name: 'get_weather',
    description: 'Get current weather for a city',
    parameters: {
      type: 'object',
      properties: { city: { type: 'string', description: 'City name' } },
      required: ['city'],
    },
  },
};

const SEARCH_TOOL: AgenticToolDefinition = {
  type: 'function',
  function: { name: 'network/search', description: 'Search the network' },
};

function call(name: string, args: Record<string, unknown>, id = 'call_test'): AgenticToolCall {
  return { id, type: 'function', function: { name, arguments: JSON.stringify(args) } };
}

describe('resolveNativeToolFamily', () => {
  it('maps qwen-chatml and mistral-v3-instruct by default', () => {
    expect(resolveNativeToolFamily('qwen-chatml')).toBe('qwen');
    expect(resolveNativeToolFamily('mistral-v3-instruct')).toBe('mistral-v3');
  });

  it('requires explicit opt-in for gemma4', () => {
    expect(resolveNativeToolFamily('gemma4')).toBeNull();
    expect(resolveNativeToolFamily('gemma4', { gemma4Enabled: false })).toBeNull();
    expect(resolveNativeToolFamily('gemma4', { gemma4Enabled: true })).toBe('gemma4');
  });

  it('returns null for families without a native format', () => {
    expect(resolveNativeToolFamily('gemma')).toBeNull();
    expect(resolveNativeToolFamily('llama3')).toBeNull();
    expect(resolveNativeToolFamily('zephyr')).toBeNull();
    expect(resolveNativeToolFamily('raw')).toBeNull();
  });
});

describe('Qwen native tool-calling', () => {
  it('formats a tools declaration block with the exact spec tags', () => {
    const block = formatQwenToolsSystemBlock([WEATHER_TOOL]);
    expect(block).toContain('# Tools');
    expect(block).toContain('<tools>');
    expect(block).toContain('</tools>');
    expect(block).toContain('<tool_call></tool_call>');
    expect(block).toContain(JSON.stringify({ type: 'function', function: WEATHER_TOOL.function }));
  });

  it('returns empty string for zero tools', () => {
    expect(formatQwenToolsSystemBlock([])).toBe('');
  });

  it('parses a single valid tool call', () => {
    const output = 'Let me check.\n<tool_call>\n{"name": "get_weather", "arguments": {"city": "Paris"}}\n</tool_call>';
    const parsed = parseQwenNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed).not.toBeNull();
    expect(parsed!.toolCalls).toHaveLength(1);
    expect(parsed!.toolCalls![0]!.function.name).toBe('get_weather');
    expect(JSON.parse(parsed!.toolCalls![0]!.function.arguments)).toEqual({ city: 'Paris' });
    expect(parsed!.text).toBe('Let me check.');
  });

  it('parses multiple consecutive tool calls', () => {
    const output =
      '<tool_call>\n{"name": "get_weather", "arguments": {"city": "Paris"}}\n</tool_call>\n<tool_call>\n{"name": "network/search", "arguments": {"query": "x"}}\n</tool_call>';
    const parsed = parseQwenNativeToolCalls(output, new Set(['get_weather', 'network/search']));
    expect(parsed!.toolCalls).toHaveLength(2);
  });

  it('rejects a hallucinated tool name (found markers, no valid calls)', () => {
    const output = '<tool_call>\n{"name": "made_up_tool", "arguments": {}}\n</tool_call>';
    const parsed = parseQwenNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed).not.toBeNull();
    expect(parsed!.toolCalls).toBeNull();
  });

  it('treats malformed JSON inside a real tag as found-markers-no-calls, not a fall-through', () => {
    const output = '<tool_call>\n{"name": "get_weather", "arguments": {city: "Paris"\n</tool_call>';
    const parsed = parseQwenNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed).not.toBeNull();
    expect(parsed!.toolCalls).toBeNull();
  });

  it('returns null (fall-through signal) when there are no native markers at all', () => {
    expect(parseQwenNativeToolCalls('just a plain prose answer')).toBeNull();
  });

  it('formats a tool result turn', () => {
    expect(formatQwenToolResultTurn('{"temperature":15}')).toBe(
      '<tool_response>\n{"temperature":15}\n</tool_response>',
    );
  });

  it('re-renders a past assistant tool_calls message in native shape', () => {
    const rendered = formatQwenAssistantToolCallTurn([call('get_weather', { city: 'Paris' })]);
    expect(rendered).toBe('<tool_call>\n{"name":"get_weather","arguments":{"city":"Paris"}}\n</tool_call>');
  });
});

describe('Mistral native tool-calling', () => {
  it('builds the [AVAILABLE_TOOLS] segment with OpenAI-shaped tool objects', () => {
    const segment = buildMistralAvailableToolsSegment([WEATHER_TOOL]);
    expect(segment.startsWith('[AVAILABLE_TOOLS] [')).toBe(true);
    expect(segment.endsWith('[/AVAILABLE_TOOLS]')).toBe(true);
    expect(segment).toContain('"type":"function"');
  });

  it('returns empty string for zero tools', () => {
    expect(buildMistralAvailableToolsSegment([])).toBe('');
  });

  it('generates a 9-character alphanumeric call id', () => {
    const id = generateMistralToolCallId();
    expect(id).toHaveLength(9);
    expect(id).toMatch(/^[A-Za-z0-9]{9}$/);
  });

  it('generates deterministic ids with a seeded random', () => {
    const seeded = () => 0; // always picks alphabet[0] = 'A'
    expect(generateMistralToolCallId(seeded)).toBe('AAAAAAAAA');
  });

  it('parses a valid [TOOL_CALLS] block preserving the model-emitted id', () => {
    const output = '[TOOL_CALLS] [{"name": "get_weather", "arguments": {"city": "Paris"}, "id": "VvvODy9mT"}]';
    const parsed = parseMistralNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed!.toolCalls).toHaveLength(1);
    expect(parsed!.toolCalls![0]!.id).toBe('VvvODy9mT');
  });

  it('parses multiple calls in one [TOOL_CALLS] array', () => {
    const output =
      '[TOOL_CALLS] [{"name":"get_weather","arguments":{"city":"Paris"},"id":"aaaaaaaaa"},{"name":"network/search","arguments":{"query":"x"},"id":"bbbbbbbbb"}]';
    const parsed = parseMistralNativeToolCalls(output, new Set(['get_weather', 'network/search']));
    expect(parsed!.toolCalls).toHaveLength(2);
  });

  it('generates an id when the model omits one', () => {
    const output = '[TOOL_CALLS] [{"name": "get_weather", "arguments": {}}]';
    const parsed = parseMistralNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed!.toolCalls![0]!.id).toHaveLength(9);
  });

  it('rejects a hallucinated tool name', () => {
    const output = '[TOOL_CALLS] [{"name": "made_up_tool", "arguments": {}, "id": "VvvODy9mT"}]';
    const parsed = parseMistralNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed!.toolCalls).toBeNull();
  });

  it('treats invalid JSON inside a closed [TOOL_CALLS] array as found-markers-no-calls', () => {
    // Brackets are balanced (so the marker is recognized) but the body isn't
    // valid JSON (unquoted key) — distinct from the "no marker at all" case.
    const output = '[TOOL_CALLS] [{"name": "get_weather", "arguments": {unquoted: true}}]';
    const parsed = parseMistralNativeToolCalls(output, new Set(['get_weather']));
    expect(parsed).not.toBeNull();
    expect(parsed!.toolCalls).toBeNull();
  });

  it('returns null (fall-through) when the array is truncated with no closing bracket at all', () => {
    // A genuinely cut-off completion (max_tokens hit mid-array) has no
    // syntactic marker to recognize yet — falls through to the generic parser.
    const output = '[TOOL_CALLS] [{"name": "get_weather", "argum';
    expect(parseMistralNativeToolCalls(output, new Set(['get_weather']))).toBeNull();
  });

  it('returns null when there is no [TOOL_CALLS] marker at all', () => {
    expect(parseMistralNativeToolCalls('just a plain prose answer')).toBeNull();
  });

  it('formats the [TOOL_CALLS] segment preserving ids', () => {
    const segment = formatMistralToolCallsSegment([call('get_weather', { city: 'Paris' }, 'VvvODy9mT')]);
    expect(segment).toBe('[TOOL_CALLS] [{"name":"get_weather","arguments":{"city":"Paris"},"id":"VvvODy9mT"}]');
  });

  it('formats [TOOL_RESULTS] as a single object (not a list) with call_id', () => {
    const segment = formatMistralToolResultSegment('sunny, 15C', 'VvvODy9mT');
    expect(segment).toBe('[TOOL_RESULTS] {"content":"sunny, 15C","call_id":"VvvODy9mT"}[/TOOL_RESULTS]');
  });
});

describe('renderMistralV3InstructPrompt', () => {
  it('matches the plain [INST]...[/INST] regression shape with no tool calls', () => {
    // Same conversation shape the ORIGINAL two-pass turn-pairing renderer
    // produced — this is the byte-for-byte non-regression anchor.
    const messages: MistralRenderableMessage[] = [
      { role: 'system', content: 'You are helpful.' },
      { role: 'user', content: 'Hi' },
      { role: 'assistant', content: 'Hello!' },
      { role: 'user', content: 'How are you?' },
    ];
    expect(renderMistralV3InstructPrompt(messages)).toBe(
      '[INST] You are helpful.\n\nHi [/INST] Hello!</s>[INST] How are you? [/INST]',
    );
  });

  it('matches the original grouping behavior for consecutive user messages with no assistant reply', () => {
    const messages: MistralRenderableMessage[] = [
      { role: 'user', content: 'first' },
      { role: 'user', content: 'second' },
    ];
    expect(renderMistralV3InstructPrompt(messages)).toBe('[INST] first [/INST][INST] second [/INST]');
  });

  it('prepends the [AVAILABLE_TOOLS] preamble once, before the first [INST]', () => {
    const messages: MistralRenderableMessage[] = [{ role: 'user', content: "What's 2+2?" }];
    const rendered = renderMistralV3InstructPrompt(messages, [
      {
        type: 'function',
        function: {
          name: 'calculator',
          description: 'Performs mathematical calculations',
          parameters: {
            type: 'object',
            properties: { operation: { type: 'string' } },
            required: ['operation'],
          },
        },
      },
    ]);
    expect(rendered.startsWith('[AVAILABLE_TOOLS] [')).toBe(true);
    expect(rendered).toContain("[/AVAILABLE_TOOLS][INST] What's 2+2? [/INST]");
  });

  it('renders the full tool round-trip matching Mistral’s own cookbook example shape', () => {
    // Mirrors the verified real example: [INST]...[/INST][TOOL_CALLS] [...]</s>
    // [TOOL_RESULTS] {...}[/TOOL_RESULTS] final_answer</s> — no [INST] wrapper
    // around the tool results or the final answer.
    const messages: MistralRenderableMessage[] = [
      { role: 'user', content: "What's 2+2?" },
      {
        role: 'assistant',
        content: '',
        tool_calls: [
          {
            id: 'VvvODy9mT',
            type: 'function',
            function: { name: 'calculator', arguments: JSON.stringify({ operation: '2+2' }) },
          },
        ],
      },
      { role: 'tool', content: '4', tool_call_id: 'VvvODy9mT' },
      { role: 'assistant', content: '2+2=4' },
    ];
    const rendered = renderMistralV3InstructPrompt(messages);
    expect(rendered).toBe(
      "[INST] What's 2+2? [/INST]" +
        '[TOOL_CALLS] [{"name":"calculator","arguments":{"operation":"2+2"},"id":"VvvODy9mT"}]</s>' +
        '[TOOL_RESULTS] {"content":"4","call_id":"VvvODy9mT"}[/TOOL_RESULTS]' +
        ' 2+2=4</s>',
    );
  });

  it('renders multiple tool calls in a single round', () => {
    const messages: MistralRenderableMessage[] = [
      { role: 'user', content: 'Weather and search please.' },
      {
        role: 'assistant',
        content: '',
        tool_calls: [
          { id: 'aaaaaaaaa', type: 'function', function: { name: 'get_weather', arguments: '{"city":"Paris"}' } },
          { id: 'bbbbbbbbb', type: 'function', function: { name: 'network/search', arguments: '{"query":"x"}' } },
        ],
      },
      { role: 'tool', content: 'sunny', tool_call_id: 'aaaaaaaaa' },
      { role: 'tool', content: 'results found', tool_call_id: 'bbbbbbbbb' },
      { role: 'assistant', content: 'Done.' },
    ];
    const rendered = renderMistralV3InstructPrompt(messages);
    expect(rendered).toContain(
      '[TOOL_CALLS] [{"name":"get_weather","arguments":{"city":"Paris"},"id":"aaaaaaaaa"},{"name":"network/search","arguments":{"query":"x"},"id":"bbbbbbbbb"}]</s>',
    );
    expect(rendered).toContain('[TOOL_RESULTS] {"content":"sunny","call_id":"aaaaaaaaa"}[/TOOL_RESULTS]');
    expect(rendered).toContain('[TOOL_RESULTS] {"content":"results found","call_id":"bbbbbbbbb"}[/TOOL_RESULTS]');
    expect(rendered.endsWith(' Done.</s>')).toBe(true);
  });

  it('handles a dangling final user message with no reply yet (mid-generation)', () => {
    const messages: MistralRenderableMessage[] = [
      { role: 'user', content: 'first' },
      { role: 'assistant', content: 'reply' },
      { role: 'user', content: 'second, awaiting generation' },
    ];
    expect(renderMistralV3InstructPrompt(messages)).toBe(
      '[INST] first [/INST] reply</s>[INST] second, awaiting generation [/INST]',
    );
  });
});

describe('Gemma4 native tool-calling (experimental)', () => {
  it('formats a tool declaration block using the mini-DSL', () => {
    const block = formatGemma4ToolDeclarationBlock([WEATHER_TOOL]);
    expect(block).toContain('<|tool>declaration:get_weather{');
    expect(block).toContain('<tool|>');
    expect(block).toContain('<|"|>Get current weather for a city<|"|>');
  });

  it('parses a single valid tool call from the mini-DSL', () => {
    const output = '<|tool_call>call:get_weather{city:<|"|>Tokyo, JP<|"|>}<tool_call|>';
    const parsed = parseGemma4NativeToolCalls(output, new Set(['get_weather']));
    expect(parsed!.toolCalls).toHaveLength(1);
    expect(JSON.parse(parsed!.toolCalls![0]!.function.arguments)).toEqual({ city: 'Tokyo, JP' });
  });

  it('handles nested objects via balanced-brace scanning', () => {
    const output =
      '<|tool_call>call:get_weather{location:{city:<|"|>Tokyo<|"|>,country:<|"|>JP<|"|>}}<tool_call|>';
    const parsed = parseGemma4NativeToolCalls(output, new Set(['get_weather']));
    expect(JSON.parse(parsed!.toolCalls![0]!.function.arguments)).toEqual({
      location: { city: 'Tokyo', country: 'JP' },
    });
  });

  it('parses multiple consecutive calls', () => {
    const output =
      '<|tool_call>call:get_weather{city:<|"|>Paris<|"|>}<tool_call|><|tool_call>call:network/search{query:<|"|>x<|"|>}<tool_call|>';
    const parsed = parseGemma4NativeToolCalls(output, new Set(['get_weather', 'network/search']));
    expect(parsed!.toolCalls).toHaveLength(2);
  });

  it('rejects a hallucinated tool name', () => {
    const output = '<|tool_call>call:made_up{x:1}<tool_call|>';
    const parsed = parseGemma4NativeToolCalls(output, new Set(['get_weather']));
    expect(parsed!.toolCalls).toBeNull();
  });

  it('returns null when there are no native markers at all', () => {
    expect(parseGemma4NativeToolCalls('just a plain prose answer')).toBeNull();
  });

  it('formats a tool-call turn and a result turn', () => {
    const turn = formatGemma4ToolCallTurn([call('get_weather', { city: 'Tokyo' })]);
    expect(turn).toBe('<|tool_call>call:get_weather{city:<|"|>Tokyo<|"|>}<tool_call|>');
    const result = formatGemma4ToolResultTurn('{"temperature":15}', 'get_weather');
    expect(result).toBe('<|tool_response>response:get_weather{temperature:15}<tool_response|>');
  });
});

describe('dispatchers', () => {
  const families: NativeToolFamily[] = ['qwen', 'mistral-v3', 'gemma4'];

  it('formatNativeToolsDeclaration routes to the right formatter per family', () => {
    expect(formatNativeToolsDeclaration('qwen', [WEATHER_TOOL]).systemAddition).toContain('<tools>');
    expect(formatNativeToolsDeclaration('mistral-v3', [WEATHER_TOOL]).preamble).toContain('[AVAILABLE_TOOLS]');
    expect(formatNativeToolsDeclaration('gemma4', [WEATHER_TOOL]).systemAddition).toContain('<|tool>declaration:');
  });

  it('parseNativeToolCalls routes to the right parser per family and all fall through on plain prose', () => {
    for (const family of families) {
      expect(parseNativeToolCalls(family, 'just a plain prose answer')).toBeNull();
    }
    expect(parseNativeToolCalls('qwen', '<tool_call>\n{"name":"get_weather","arguments":{}}\n</tool_call>', new Set(['get_weather']))!.toolCalls).toHaveLength(1);
    expect(parseNativeToolCalls('mistral-v3', '[TOOL_CALLS] [{"name":"get_weather","arguments":{},"id":"aaaaaaaaa"}]', new Set(['get_weather']))!.toolCalls).toHaveLength(1);
    expect(parseNativeToolCalls('gemma4', '<|tool_call>call:get_weather{}<tool_call|>', new Set(['get_weather']))!.toolCalls).toHaveLength(1);
  });
});
